import{_ as s,o as i,c as a,ai as t}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Pi 开发工作流程","description":"","frontmatter":{"title":"Pi 开发工作流程","x-i18n":{"generated_at":"2026-02-03T10:07:59Z","model":"claude-opus-4-5","provider":"pi","source_hash":"65bd0580dd03df05321ced35a036ce6fb815ce3ddac1d35c9976279adcbf87c0","source_path":"pi-dev.md","workflow":15}},"headers":[],"relativePath":"zh-CN/pi-dev.md","filePath":"zh-CN/pi-dev.md","lastUpdated":null}'),d={name:"zh-CN/pi-dev.md"};function l(o,e,n,p,c,r){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="pi-开发工作流程" tabindex="-1"><a class="header-anchor" href="#pi-开发工作流程">#</a> Pi 开发工作流程</h1><p>本指南总结了在 OpenSoul 中开发 Pi 集成的合理工作流程。</p><h2 id="类型检查和代码检查" tabindex="-1"><a class="header-anchor" href="#类型检查和代码检查">#</a> 类型检查和代码检查</h2><ul><li>类型检查和构建：<code>pnpm build</code></li><li>代码检查：<code>pnpm lint</code></li><li>格式检查：<code>pnpm format</code></li><li>推送前完整检查：<code>pnpm lint &amp;&amp; pnpm build &amp;&amp; pnpm test</code></li></ul><h2 id="运行-pi-测试" tabindex="-1"><a class="header-anchor" href="#运行-pi-测试">#</a> 运行 Pi 测试</h2><p>使用专用脚本运行 Pi 集成测试集：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/pi/run-tests.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>要包含执行真实提供商行为的实时测试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/pi/run-tests.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --live</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该脚本通过以下 glob 模式运行所有 Pi 相关的单元测试：</p><ul><li><code>src/agents/pi-*.test.ts</code></li><li><code>src/agents/pi-embedded-*.test.ts</code></li><li><code>src/agents/pi-tools*.test.ts</code></li><li><code>src/agents/pi-settings.test.ts</code></li><li><code>src/agents/pi-tool-definition-adapter.test.ts</code></li><li><code>src/agents/pi-extensions/*.test.ts</code></li></ul><h2 id="手动测试" tabindex="-1"><a class="header-anchor" href="#手动测试">#</a> 手动测试</h2><p>推荐流程：</p><ul><li>以开发模式运行 Gateway 网关： <ul><li><code>pnpm gateway:dev</code></li></ul></li><li>直接触发智能体： <ul><li><code>pnpm opensoul agent --message &quot;Hello&quot; --thinking low</code></li></ul></li><li>使用 TUI 进行交互式调试： <ul><li><code>pnpm tui</code></li></ul></li></ul><p>对于工具调用行为，提示执行 <code>read</code> 或 <code>exec</code> 操作，以便查看工具流式传输和负载处理。</p><h2 id="完全重置" tabindex="-1"><a class="header-anchor" href="#完全重置">#</a> 完全重置</h2><p>状态存储在 OpenSoul 状态目录下。默认为 <code>~/.opensoul</code>。如果设置了 <code>OPENSOUL_STATE_DIR</code>，则使用该目录。</p><p>要重置所有内容：</p><ul><li><code>opensoul.json</code> 用于配置</li><li><code>credentials/</code> 用于认证配置文件和 token</li><li><code>agents/&lt;agentId&gt;/sessions/</code> 用于智能体会话历史</li><li><code>agents/&lt;agentId&gt;/sessions.json</code> 用于会话索引</li><li><code>sessions/</code> 如果存在旧版路径</li><li><code>workspace/</code> 如果你想要一个空白工作区</li></ul><p>如果只想重置会话，删除该智能体的 <code>agents/&lt;agentId&gt;/sessions/</code> 和 <code>agents/&lt;agentId&gt;/sessions.json</code>。如果不想重新认证，保留 <code>credentials/</code>。</p><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料">#</a> 参考资料</h2><ul><li><a href="https://docs.opensoul.ai/testing" target="_blank" rel="noreferrer">https://docs.opensoul.ai/testing</a></li><li><a href="https://docs.opensoul.ai/start/getting-started" target="_blank" rel="noreferrer">https://docs.opensoul.ai/start/getting-started</a></li></ul>',22)])])}const g=s(d,[["render",l]]);export{u as __pageData,g as default};
